import{_ as t,o,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"94. Rosters","description":"","frontmatter":{"title":"94. Rosters","eba":"Mental Health Services 2024-2028","topics":["hours","rosters","union-matters"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/94-rosters.md","filePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/94-rosters.md"}'),n={name:"ebas/mental-health/rpn-pen-mho/hours-of-work/94-rosters.md"};function a(i,e,l,h,p,c){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_94-rosters" tabindex="-1">94. Rosters <a class="header-anchor" href="#_94-rosters" aria-label="Permalink to &quot;94. Rosters&quot;">​</a></h1><p>This clause does not apply to casuals and Employees above the level of RPN5</p><p><strong>94.1</strong> Posting of Roster</p><p><strong>(a)</strong> Subject to clause 94.10 (employees not required to have a roster), the ordinary hours of duty for full time and part time Employees shall be worked according to a written roster that will:</p><p><strong>(i)</strong> be of at least 28 days duration</p><p><strong>(ii)</strong> be posted at least 28 days before it comes into operation in each work location where it can be readily seen by such Employees and/or other representatives of the Union(s) for the purpose of ensuring compliance with the rostering provisions of this Agreement.</p><p><strong>(iii)</strong> as far as practicable reflect the roster each Employee will work.</p><p><strong>(b)</strong> Nothing in this clause precludes an Employer issuing the roster or the on-call roster in electronic form.</p><p><strong>94.2</strong> Rosters will:</p><p><strong>(a)</strong> set out:</p><p><strong>(i)</strong> the Employee’s ordinary working hours</p><p><strong>(ii)</strong> starting and finishing times</p><p><strong>(iii)</strong> meal intervals.</p><p><strong>(b)</strong> have a staffing mix that complies with sub-<a href="/eba/ebas/mental-health/rpn-pen-mho/classification-staffing/101-staffing.html">clauses 101.9</a> and 101.10 if applicable;</p><p><strong>(c)</strong> allocate a RPN to be in charge if applicable; and</p><p><strong>(d)</strong> not change without at least fourteen days’ notice of a change in roster other than in an emergency situation external to the employer, subject to clause 94.3 below.</p><p><strong>(e)</strong> Provide an Employee who works 0.8 EFT or more with two consecutive days off per week. Nothing in this subclause (e) is intended to:</p><p><strong>(i)</strong> restrict an Employee requesting single days off, including as a self rostering request; or</p><p><strong>(ii)</strong> prevent an Employee who works 0.8 EFT or more from having a single day off rostered where they also have consecutive days off rostered that week.</p><p><strong>(f)</strong> From the commencement of the Agreement, an Employer may use an alternative method to record meal interval allocations outlined in 94.2(a)(iii) if the electronic roster system being used is unable to accommodate its inclusion. This will be located in each work location where it can be readily accessible by such Employees and/or other representatives of the Union(s) to ensure compliance with meal break provisions, for a period of no less than 6 years.</p><p><strong>94.3</strong> Breaks between rostered shifts The roster or rosters will be drawn up to so as to provide at least eight hours between successive shifts.</p><p><strong>94.4</strong> Roster Not Posted at least 28 days before it comes into operation</p><p><strong>(a)</strong> Where a roster is not posted 28 days in advance as required by clause 94.1, each shift in the roster that is worked with less than 28 days&#39; notice shall attract a change of roster allowance as prescribed at subclause 94.8(ii) (change of roster allowance).</p><p>Example: A roster for a ward was posted 25 days before coming into effect, rather than 28 days as required by clause 94.1. A change of roster is payable for those shifts worked on the roster with less than 28 days&#39; notice.</p><p><strong>(b)</strong> The provisions of subclause 94.1 do not apply where:</p><p><strong>(i)</strong> In respect of a shift that the Employee agrees to work as an additional shift under the supplementary roster</p><p><strong>(ii)</strong> In respect of a shift that the Employee works that already attracts the Change of Roster allowance under clause 94.8 (change of roster allowance);</p><p><strong>(iii)</strong> The shift was not rostered in advance because the Employee swapped shifts by agreement with another Employee; or</p><p><strong>(iv)</strong> The roster is varied in accordance with this Agreement, for example clauses 94.6 and 94.8.</p><p><strong>94.5</strong> Roster Arrangements</p><p><strong>(a)</strong> The following rostering principles will apply:</p><p><strong>(i)</strong> Unless by agreement, shift changes shall be avoided during the roster period</p><p><strong>(ii)</strong> There shall be an equitable allocation of rostered time on and off on weekends and public holidays among all Employees</p><p><strong>(b)</strong> Subject to practicality and service requirements, the Employer will ensure that:</p><p><strong>(i)</strong> Employees will not be rostered for more than six consecutive days or more than four consecutive nights unless otherwise agreed at the initiative and written request of the Employee and then agreed in writing</p><p><strong>(ii)</strong> single days/nights off will be minimised; and</p><p><strong>(iii)</strong> rostered days off shall be attached to either 2 consecutive days/night off or to a single day/night off.</p><p><strong>(c)</strong> The roster shall be drawn up so as to provide at least eight hours off duty between successive ordinary shifts</p><p><strong>(d)</strong> All Employees shall receive at least one clear day off in each week in the case of dayshift Employees and one clear night off in each week in the case of night shift Employees.</p><p><strong>(e)</strong> Nothing in this Agreement is intended to disturb local rostering arrangements or arrangements with the Employer.</p><p><strong>94.6</strong> Fixed Rosters</p><p><strong>(a)</strong> An Employee, by making a written request to the Employer, may have a roster fixed by mutual agreement (subject to the other provisions of this Agreement) in lieu of the provisions of subclauses 94.1 to 94.2 save that:</p><p><strong>(i)</strong> an Employer will not unreasonably refuse a request for a fixed roster agreement where the Employee can demonstrate a regular and systematic pattern of work (as defined below); <strong>(A)</strong> regular and systematic pattern of work means working set days or shifts in a demonstrable pattern over the preceding six months (recognising that additional ordinary shifts may be worked around that fixed pattern); but <strong>(B)</strong> does not include shifts worked because the Employee who usually works them is on extended leave.</p><p><strong>(ii)</strong> where a fixed roster agreement is made, the Employer will provide the Employee with an amended Letter of Appointment detailing the fixed roster agreement which will be consistent with the regular and systematic pattern of work described at (A) and (B) above; and</p><p><strong>(iii)</strong> where the Employer proposes to change the Employee&#39;s fixed roster agreement, the terms of subclause 18 (Consultation) or <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/19-consultation-about-changes-to-rosters-or-hours-or-work.html">clause 19</a> (Consultation about changes to rosters or hours or work) will apply, depending on the circumstances.</p><p><strong>(b)</strong> A written request for a fixed roster may be made in circumstances where the Employer is proposing to alter, or has recently altered, the Employee&#39;s regular and systematic pattern of work.</p><p><strong>(c)</strong> An Employee may end the fixed roster agreement at any time by giving written notice to the Employer. In such a case the roster for the Employee will be set according to the provisions of subclauses 94.1 to 94.2 above from the commencement of the next full roster period being not less than five clear days after the written notice is received.</p><p><strong>94.7</strong> On-Call Rosters The intent of this subclause is to ensure Employees have a reasonably predictable pattern of work during the on-call roster period. This clause does not apply to casual Employees, DON’s or Deputy DON’s.</p><p><strong>(a)</strong> Planned on-call arrangement means the on-call arrangements the Employer would reasonably expect to be required within the work location at the time the on- call roster is released.</p><p><strong>(b)</strong> Planned on-call arrangements for full-time and part-time Employees will be:</p><p><strong>(i)</strong> worked according to a written roster of at least 28 days duration; and</p><p><strong>(ii)</strong> posted at least 28 days before it comes into operation in each work location where it can be readily seen by Employees and representatives of the Employees, including the Union without notice.</p><p><strong>(c)</strong> Nothing in this clause prevents an Employer placing an Employee on-call in circumstances where the requirement for the Employee to be rostered on-call was not known at the time the roster was released, save that where this occurs, the allowance at 94.8 applies.</p><p><strong>(d)</strong> On-call/recall payments are located at 91 and <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>94.8</strong> Change of Roster Allowance If the Employer changes an Employee&#39;s roster or planned on call roster once set in accordance with subclauses 94.1 or 94.7(on-call roster), other than as excepted in 94.2(d), the Change of Roster Allowance will apply in relation to each change as follows:</p><p><strong>(i)</strong> 7 days&#39; or less notice, the applicable rate in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>,</p><p><strong>(ii)</strong> 8 to 14 days&#39; notice, the applicable rate in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>. This allowance is not payable to a part-time Employee for an additional shift worked unless the circumstances described in subclause 95 (Supplementary Roster) apply.</p><p><strong>(b)</strong> If an additional shift is worked by a part-time Employee other than under the supplementary roster, it attracts the Change of Roster Allowance as described at subclause 94.8(ii) above,</p><p><strong>(c)</strong> This clause 94.8 does not apply to those circumstances covered by <a href="/eba/ebas/mental-health/rpn-pen-mho/allowances/84A-change-of-ward-allowance.html">clause 84A</a> (Change of Ward Allowance) unless the start and/or finish time on the Employee’s roster, in relation to ordinary hours, also change</p><p><strong>94.9</strong> Rosters which include work on public holiday</p><p><strong>(a)</strong> Employers must implement a policy or procedure for the issuance and finalisation of rosters which cover the performance of work on a public holiday under the Act.</p><p><strong>(b)</strong> The policy / procedure referenced at subclause 94.9(a) above should:</p><p><strong>(i)</strong> set out the process for an Employee to request not to work on a public holiday they are requested to work; and</p><p><strong>(ii)</strong> set out the process for the Employer to provide a written response to an Employee&#39;s request not to work on a public holiday they are requested to work</p><p><strong>(c)</strong> An Employer who receives a request under subclause 94.9(b)(i) must accept that request unless the Employer determines that the refusal is not reasonable in the circumstances. The factors an Employer must consider when determining whether a request is not reasonable include:</p><p><strong>(i)</strong> whether the Employee has clearly explained a reason for refusing to work on the relevant public holiday</p><p><strong>(ii)</strong> the nature of the Employers’ workplace or enterprise (including its operational requirements), and the nature of the work performed by the Employee</p><p><strong>(iii)</strong> the capacity for the Employer to find a replacement Employee to perform the same work</p><p><strong>(iv)</strong> the Employee’s personal circumstances (including family responsibilities) to the extent that those circumstances have been disclosed to the Employer</p><p><strong>(v)</strong> whether the Employee could reasonably have expected the Employer to request that they work on the public holiday(s)</p><p><strong>(vi)</strong> whether the Employee is entitled to receive overtime payments, penalty rates or other compensation for, or a level of remuneration that reflects expectation of, work on the public holiday(s)</p><p><strong>(vii)</strong> the type of employment of the Employee (e.g., whether full-time, part- time, casual or shiftwork);</p><p><strong>(viii)</strong> the amount of notice in advance of the public holiday given by the Employer when making the request</p><p><strong>(ix)</strong> the amount of notice in advance of the public holiday given by the Employee when refusing the request</p><p><strong>(x)</strong> the number of public holidays the Employee has previously worked and been required to work in recent roster durations; and</p><p><strong>(xi)</strong> any other relevant matter.</p><p><strong>(d)</strong> Where the Employer has requested an Employee to work any public holiday(s) and either:</p><p><strong>(i)</strong> the Employee has not made a request not to work the public holiday in accordance with the policy or procedure referenced at subclause above; or</p><p><strong>(ii)</strong> the Employer has determined that a request was not reasonable (taking into account the factors in subclause 94.9(c)), the Employer may require the Employee to work on the relevant public holiday(s).</p><p><strong>94.10</strong> Employees not required to have a roster</p><p><strong>(a)</strong> The requirement to have a roster at clause 94.1 and payments for failing to post a roster at clauses 94.1 and 94.6 do not apply to those Employees who are genuinely not required to work in accordance with a roster. Whether an Employee is genuinely not required to work in accordance with a roster shall be determined on the circumstances including:</p><p><strong>(i)</strong> The nature of the role and the environment in which it operates</p><p><strong>(ii)</strong> The practice at the worksite; and/or</p><p><strong>(iii)</strong> That the Employee’s work hours are set or self-directed.</p><p><strong>(b)</strong> This clause 94.10 does not limit an Employer’s obligations in respect to on-call rosters.</p><p><strong>(c)</strong> By not later than 6 months after the commencement of the Agreement the Employer will provide the WIC with a list of existing Employee positions it says do not work in accordance with a roster. Any disputes about whether such Employees are genuinely not required to work in accordance with a roster (for the purposes of subclause (a) above) that are not resolved at the WIC will be referred to the Central Implementation Committee.</p><p><strong>(d)</strong> Where the Employer is proposing to create a position to which this clause 94.10 applies, this information will be included in the change impact statement required under <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/18-consultation.html">clause 18</a> (Consultation).</p><p>Plain language terms: rostering, shift roster, duty roster, roster changes.</p>',88)])])}const m=t(n,[["render",a]]);export{g as __pageData,m as default};
